import { existsSync, mkdtempSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { constants as fsConstants } from 'node:fs';
import { accessSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, join, resolve } from 'node:path';
import { spawnSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { describe, expect, it } from 'vitest';

const gnosisRoot = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const wrapperPath = join(gnosisRoot, 'bin', 'rtlsdr-mock-sim.js');

/** Pretty-printed CLI emits one or more JSON objects; replay + rotated emits two. */
function parseJsonBlocks(stdout: string): unknown[] {
  const out: unknown[] = [];
  let depth = 0;
  let start = -1;
  for (let i = 0; i < stdout.length; i++) {
    const c = stdout[i];
    if (c === '{') {
      if (depth === 0) start = i;
      depth++;
    } else if (c === '}') {
      depth--;
      if (depth === 0 && start >= 0) {
        const slice = stdout.slice(start, i + 1);
        out.push(JSON.parse(slice) as unknown);
        start = -1;
      }
    }
  }
  return out;
}

function lastJsonRecord(stdout: string): Record<string, unknown> {
  const blocks = parseJsonBlocks(stdout);
  expect(blocks.length).toBeGreaterThan(0);
  const last = blocks[blocks.length - 1];
  expect(typeof last).toBe('object');
  expect(last).not.toBeNull();
  return last as Record<string, unknown>;
}

function runWrapper(
  args: string[],
  extraEnv?: NodeJS.ProcessEnv,
): { status: number | null; stdout: string; stderr: string } {
  const r = spawnSync(process.execPath, [wrapperPath, ...args], {
    cwd: gnosisRoot,
    encoding: 'utf8',
    env: { ...process.env, ...extraEnv },
  });
  return { status: r.status, stdout: r.stdout ?? '', stderr: r.stderr ?? '' };
}

function assertExecutable(p: string): void {
  accessSync(p, fsConstants.X_OK);
}

describe('rtlsdr-mock-sim CLI (subprocess integration)', () => {
  it('synthetic: writes u8 + wav and prints mode JSON', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-cli-syn-'));
    const u8 = join(dir, 'out.u8');
    const wav = join(dir, 'out.wav');
    const { status, stdout, stderr } = runWrapper([
      'synthetic',
      '--seconds',
      '0.08',
      '--noise-rms',
      '0',
      '--iq-rate',
      '2048000',
      '--u8-out',
      u8,
      '--wav-out',
      wav,
    ]);
    expect(status, `stderr: ${stderr}`).toBe(0);
    expect(existsSync(u8)).toBe(true);
    expect(existsSync(wav)).toBe(true);
    expect(readFileSync(u8).length).toBeGreaterThan(1000);
    expect(readFileSync(wav).length).toBeGreaterThan(1000);
    const j = lastJsonRecord(stdout);
    expect(j['mode']).toBe('synthetic');
    expect(j['u8Out']).toBe(u8);
    expect(j['wavOut']).toBe(wav);
  });

  it('replay: accepts synthetic u8 and writes wav', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-cli-rep-'));
    const u8 = join(dir, 'in.u8');
    const synWav = join(dir, 'syn.wav');
    const repWav = join(dir, 'rep.wav');
    const s1 = runWrapper([
      'synthetic',
      '--seconds',
      '0.06',
      '--noise-rms',
      '0',
      '--iq-rate',
      '2048000',
      '--u8-out',
      u8,
      '--wav-out',
      synWav,
    ]);
    expect(s1.status, s1.stderr).toBe(0);
    const s2 = runWrapper([
      'replay',
      '--iq-file',
      u8,
      '--iq-rate',
      '2048000',
      '--wav-out',
      repWav,
    ]);
    expect(s2.status, s2.stderr).toBe(0);
    expect(existsSync(repWav)).toBe(true);
    const j = lastJsonRecord(s2.stdout);
    expect(j['mode']).toBe('replay');
    expect(j['iqFile']).toBe(resolve(u8));
  });

  it('replay: --also-write-rotated-u8 emits second JSON and writes rotated file', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-cli-rot-'));
    const u8 = join(dir, 'in.u8');
    const rot = join(dir, 'rot.u8');
    const wav = join(dir, 'out.wav');
    const s0 = runWrapper([
      'synthetic',
      '--seconds',
      '0.05',
      '--noise-rms',
      '0',
      '--iq-rate',
      '2048000',
      '--u8-out',
      u8,
      '--wav-out',
      join(dir, 'syn.wav'),
    ]);
    expect(s0.status).toBe(0);
    const s1 = runWrapper([
      'replay',
      '--iq-file',
      u8,
      '--iq-rate',
      '2048000',
      '--wav-out',
      wav,
      '--also-write-rotated-u8',
      '--rotated-u8-out',
      rot,
    ]);
    expect(s1.status, s1.stderr).toBe(0);
    const blocks = parseJsonBlocks(s1.stdout);
    expect(blocks.length).toBeGreaterThanOrEqual(2);
    const first = blocks[0] as Record<string, unknown>;
    expect(first['rotatedU8']).toBe(resolve(rot));
    expect(existsSync(rot)).toBe(true);
    expect(readFileSync(rot).length).toBe(readFileSync(u8).length);
    const last = blocks[blocks.length - 1] as Record<string, unknown>;
    expect(last['mode']).toBe('replay');
  });

  it('batch: processes capture directory and writes summary + wav', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-cli-bat-'));
    const capDir = join(dir, 'captures');
    mkdirSync(capDir);
    const u8 = join(capDir, 'one.u8');
    const s0 = runWrapper([
      'synthetic',
      '--seconds',
      '0.05',
      '--noise-rms',
      '0',
      '--iq-rate',
      '2048000',
      '--u8-out',
      u8,
      '--wav-out',
      join(dir, 'unused.wav'),
    ]);
    expect(s0.status).toBe(0);
    const summaryPath = join(dir, 'batch-summary.json');
    const wavDir = join(dir, 'batch-wav');
    const s1 = runWrapper([
      'batch',
      '--capture-dir',
      capDir,
      '--iq-rate',
      '2048000',
      '--batch-summary',
      summaryPath,
      '--batch-wav-dir',
      wavDir,
    ]);
    expect(s1.status, s1.stderr).toBe(0);
    expect(existsSync(summaryPath)).toBe(true);
    const rows = JSON.parse(readFileSync(summaryPath, 'utf8')) as unknown[];
    expect(Array.isArray(rows)).toBe(true);
    expect(rows.length).toBeGreaterThanOrEqual(1);
    const wavOut = (rows[0] as { wavOut?: string }).wavOut;
    expect(typeof wavOut).toBe('string');
    expect(existsSync(wavOut!)).toBe(true);
    const j = lastJsonRecord(s1.stdout);
    expect(j['mode']).toBe('batch');
    expect(j['filesProcessed']).toBe(1);
  });

  it('fuse: merges batch summary with rtl_433 JSONL', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-cli-fuse-'));
    const capturePath = resolve(join(dir, 'cap.u8'));
    const mtimeMs = Date.now();
    const summaryPath = join(dir, 'batch-summary.json');
    writeFileSync(
      summaryPath,
      JSON.stringify([{ file: capturePath, captureMtimeMs: mtimeMs }], null, 2),
    );
    const rtlPath = join(dir, 'events.jsonl');
    writeFileSync(
      rtlPath,
      `${JSON.stringify({ model: 'integration_probe', time: new Date(mtimeMs).toISOString() })}\n`,
    );
    const fusionPath = join(dir, 'fusion.json');
    const { status, stdout, stderr } = runWrapper([
      'fuse',
      '--batch-summary',
      summaryPath,
      '--rtl433-jsonl',
      rtlPath,
      '--fusion-out',
      fusionPath,
      '--fuse-max-delta-sec',
      '180',
    ]);
    expect(status, stderr).toBe(0);
    expect(existsSync(fusionPath)).toBe(true);
    const fusion = JSON.parse(readFileSync(fusionPath, 'utf8')) as {
      matchCount?: number;
      rtl433Events?: unknown[];
    };
    expect(fusion.matchCount).toBeGreaterThanOrEqual(1);
    expect(Array.isArray(fusion.rtl433Events)).toBe(true);
    expect(fusion.rtl433Events?.length).toBe(1);
    const j = lastJsonRecord(stdout);
    expect(j['mode']).toBe('fuse');
    expect(j['fusionOutPath']).toBe(resolve(fusionPath));
  });

  it('rf-key: emits Monster RF cache-key replay envelope in simulated mode', () => {
    const { status, stdout, stderr } = runWrapper(['rf-key']);
    expect(status, stderr).toBe(0);
    const j = lastJsonRecord(stdout);
    const root = j['monsterRfCacheKey'] as Record<string, unknown>;
    expect(root['schemaVersion']).toBe('gnosis.rf-cache-key.v1');
    expect(root['transport']).toBe('simulated');
    const frame = root['frame'] as Record<string, unknown>;
    expect(frame['ascii']).toContain('GNOSIS-RFKEY/1');
    expect(frame['ascii']).toContain('prefixHash=66');
    const replay = root['replayContract'] as Record<string, unknown>;
    expect(replay['prefixHash']).toBe(66);
    expect(replay['prefixLen']).toBe(7);
    expect(replay['cachedReplay']).toBe(true);
    expect(replay['geodesicLength']).toBe(0);
  });

  it('rf-key: emits protocol69 polyglot app cache-key frame from a receipt file', () => {
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-app-receipt-'));
    const receiptPath = join(dir, 'receipt.json');
    writeFileSync(
      receiptPath,
      JSON.stringify({
        schemaVersion: 'gnosis.protocol69.polyglot-app-cache-receipt.v1',
        teleportKind: 'polyglot-app->gg->protocol69-cache-key',
        receiptReturn: 'compute-cache-key',
        keyMaterial: {
          language: 'typescript',
          filePath: 'app.ts',
          functionName: 'main',
          programChecksum: 'd9715bcf',
        },
        computeCacheKey: 'gnosis:protocol69:polyglot-app-cache:v1:9d4bd7ba',
      }),
    );
    const { status, stdout, stderr } = runWrapper([
      'rf-key',
      '--symbol-mode',
      'polyglot-app-cache-key',
      '--app-receipt-file',
      receiptPath,
    ]);
    expect(status, stderr).toBe(0);
    const j = lastJsonRecord(stdout);
    const root = j['monsterRfCacheKey'] as Record<string, unknown>;
    const appTeleport = root['appTeleport'] as Record<string, unknown>;
    const frame = appTeleport['frame'] as Record<string, unknown>;
    expect(frame['ascii']).toContain('GNOSIS-P69-APP/1');
    expect(frame['ascii']).toContain(
      'cacheKey=gnosis:protocol69:polyglot-app-cache:v1:9d4bd7ba',
    );
    expect(frame['ascii']).toContain('function=main');
  });

  it('rf-key: preflight marks Soapy transmitter unavailable when discovery fails', () => {
    const { status, stdout, stderr } = runWrapper([
      'rf-key',
      '--transport',
      'hardware',
      '--preflight-only',
      '--tx-kind',
      'soapy-sdr-tx',
      '--tx-bin',
      '/definitely/missing/SoapySDRUtil',
      '--tx-device-args',
      'driver=plutosdr',
    ]);
    expect(status, stderr).toBe(0);
    const j = lastJsonRecord(stdout);
    const root = j['monsterRfCacheKey'] as Record<string, unknown>;
    const broadcaster = root['broadcaster'] as Record<string, unknown>;
    const adapter = broadcaster['adapter'] as Record<string, unknown>;
    const discovery = adapter['discovery'] as Record<string, unknown>;
    expect(broadcaster['txAvailable']).toBe(false);
    expect(adapter['available']).toBe(false);
    expect(discovery['hardwarePresent']).toBe(false);
  });
});

const nativeEnabled = Boolean(process.env.GNOSIS_RTLSDR_NATIVE_INTEGRATION);
const nativeBin = join(gnosisRoot, 'target', 'release', 'rtlsdr-mock-sim');
function describeWhen(enabled: boolean, name: string, fn: () => void): void {
  if (enabled) describe(name, fn);
}

describeWhen(nativeEnabled, 'rtlsdr-mock-sim native binary (opt-in)', () => {
  it('synthetic via GNOSIS_RTLSDR_MOCK_SIM_BIN matches release stub layout', () => {
    if (!existsSync(nativeBin)) {
      throw new Error(
        `Missing ${nativeBin}; run: cargo build --manifest-path open-source/gnosis/rtlsdr-mock-sim-native/Cargo.toml --release --target-dir open-source/gnosis/target`,
      );
    }
    assertExecutable(nativeBin);
    const dir = mkdtempSync(join(tmpdir(), 'rtlsdr-native-'));
    const u8 = join(dir, 'n.u8');
    const wav = join(dir, 'n.wav');
    const { status, stdout, stderr } = runWrapper(
      ['synthetic', '--seconds', '0.05', '--noise-rms', '0', '--u8-out', u8, '--wav-out', wav],
      { GNOSIS_RTLSDR_MOCK_SIM_BIN: nativeBin },
    );
    expect(status, stderr).toBe(0);
    expect(existsSync(u8)).toBe(true);
    expect(existsSync(wav)).toBe(true);
    const j = lastJsonRecord(stdout);
    expect(j['mode']).toBe('synthetic');
  });
});

const hardwareEnabled = Boolean(process.env.RUN_RTLSDR_HARDWARE_TESTS);

describeWhen(hardwareEnabled, 'rtlsdr-hardware-loop.sh (opt-in, requires rtl_sdr + dongle)', () => {
  it('captures and replays through package script', () => {
    const loopDir = mkdtempSync(join(tmpdir(), 'rtlsdr-hw-loop-'));
    const scriptPath = join(gnosisRoot, 'scripts', 'rtlsdr-hardware-loop.sh');
    const r = spawnSync('bash', [scriptPath], {
      cwd: gnosisRoot,
      encoding: 'utf8',
      env: {
        ...process.env,
        RTLSDR_HW_OUT_DIR: loopDir,
        RTLSDR_HW_SAMPLES: '81920',
        RTLSDR_HW_FREQ_HZ: '100000000',
      },
    });
    expect(r.status, `${r.stderr}\n${r.stdout}`).toBe(0);
    expect(existsSync(join(loopDir, 'hardware-capture.u8'))).toBe(true);
    expect(existsSync(join(loopDir, 'hardware-capture.meta.json'))).toBe(true);
    expect(existsSync(join(loopDir, 'hardware-replay.wav'))).toBe(true);
  });
});
